+    if (!str) return '';
+    // Remove or escape characters that could break Mermaid syntax
+    return str.replace(/[\"\\]/g, ' ').replace(/[\n\r]/g, ' ').substring(0, 20);
+  }
+
+  // Build Mermaid gitgraph
